{
  "name": "Minima PiNet Web3OS",
  "description": "A futuristic, decentralized Web3 operating system interface designed for Raspberry Pi clusters running Minima nodes. Features system monitoring, node management, and an integrated AI assistant.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AppId = 'minima-node' | 'system-monitor' | 'terminal' | 'wallet' | 'ai-assistant' | 'settings';

export interface WindowState {
  id: AppId;
  title: string;
  isOpen: boolean;
  isMinimized: boolean;
  zIndex: number;
}

export interface NodeStats {
  blockHeight: number;
  peers: number;
  status: 'Synced' | 'Syncing' | 'Offline';
  uptime: string;
  version: string;
}

export interface SystemStats {
  cpu: number;
  ram: number;
  temp: number;
  disk: number;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getAiResponse = async (prompt: string, context?: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: `You are PiNet AI, the resident assistant for Minima Web3OS. 
        You help users manage their Raspberry Pi blockchain nodes. 
        Current System Context: ${JSON.stringify(context || {})}.
        Keep answers concise, technical yet accessible, and helpful for node maintenance.`,
        temperature: 0.7,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having trouble connecting to my neural core. Please check your network and try again.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import Desktop from './components/Desktop';
import Taskbar from './components/Taskbar';
import TopBar from './components/TopBar';
import { AppId, WindowState, NodeStats, SystemStats } from './types';
import MinimaNodeApp from './components/apps/MinimaNodeApp';
import SystemMonitorApp from './components/apps/SystemMonitorApp';
import TerminalApp from './components/apps/TerminalApp';
import AiAssistantApp from './components/apps/AiAssistantApp';
import WalletApp from './components/apps/WalletApp';

const App: React.FC = () => {
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'minima-node', title: 'Minima Node', isOpen: true, isMinimized: false, zIndex: 10 },
    { id: 'system-monitor', title: 'System Monitor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'terminal', title: 'Shell Terminal', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'ai-assistant', title: 'PiNet AI', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'wallet', title: 'Web3 Wallet', isOpen: false, isMinimized: false, zIndex: 1 },
  ]);

  const [activeId, setActiveId] = useState<AppId>('minima-node');
  const [nodeStats, setNodeStats] = useState<NodeStats>({
    blockHeight: 1245091,
    peers: 14,
    status: 'Synced',
    uptime: '14d 05h 22m',
    version: '1.0.35'
  });

  const [sysStats, setSysStats] = useState<SystemStats>({
    cpu: 24,
    ram: 45,
    temp: 42,
    disk: 12
  });

  // Simulate dynamic system stats
  useEffect(() => {
    const interval = setInterval(() => {
      setSysStats(prev => ({
        cpu: Math.max(10, Math.min(95, prev.cpu + (Math.random() * 10 - 5))),
        ram: Math.max(40, Math.min(60, prev.ram + (Math.random() * 2 - 1))),
        temp: Math.max(38, Math.min(65, prev.temp + (Math.random() * 4 - 2))),
        disk: prev.disk
      }));
      setNodeStats(prev => ({
        ...prev,
        blockHeight: prev.blockHeight + 1
      }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const openApp = (id: AppId) => {
    setWindows(prev => prev.map(w => {
      if (w.id === id) {
        return { ...w, isOpen: true, isMinimized: false, zIndex: Math.max(...prev.map(x => x.zIndex)) + 1 };
      }
      return w;
    }));
    setActiveId(id);
  };

  const closeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const minimizeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
  };

  const bringToFront = (id: AppId) => {
    const maxZ = Math.max(...windows.map(w => w.zIndex));
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: maxZ + 1, isMinimized: false } : w));
    setActiveId(id);
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-slate-950 flex flex-col font-sans select-none">
      {/* Background Effect */}
      <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_50%_50%,rgba(59,130,246,0.1),rgba(0,0,0,0))]" />

      <TopBar nodeStats={nodeStats} systemStats={sysStats} />

      <main className="flex-1 relative overflow-hidden p-6 mt-10 mb-16">
        <Desktop 
          openApp={openApp} 
        />

        {/* Render Windows */}
        {windows.map(win => {
          if (!win.isOpen) return null;

          return (
            <div 
              key={win.id}
              style={{ zIndex: win.zIndex, display: win.isMinimized ? 'none' : 'block' }}
              className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-4xl h-[70vh]"
            >
              <WindowContainer 
                title={win.title} 
                onClose={() => closeApp(win.id)}
                onMinimize={() => minimizeApp(win.id)}
                onFocus={() => bringToFront(win.id)}
                isActive={activeId === win.id}
              >
                {win.id === 'minima-node' && <MinimaNodeApp stats={nodeStats} />}
                {win.id === 'system-monitor' && <SystemMonitorApp stats={sysStats} />}
                {win.id === 'terminal' && <TerminalApp />}
                {win.id === 'ai-assistant' && <AiAssistantApp context={{ node: nodeStats, sys: sysStats }} />}
                {win.id === 'wallet' && <WalletApp />}
              </WindowContainer>
            </div>
          );
        })}
      </main>

      <Taskbar 
        windows={windows} 
        activeId={activeId} 
        onAppClick={(id) => {
          const win = windows.find(w => w.id === id);
          if (win?.isMinimized || !win?.isOpen) {
            openApp(id);
          } else if (activeId === id) {
            minimizeApp(id);
          } else {
            bringToFront(id);
          }
        }} 
      />
    </div>
  );
};

interface WindowContainerProps {
  title: string;
  onClose: () => void;
  onMinimize: () => void;
  onFocus: () => void;
  isActive: boolean;
  children: React.ReactNode;
}

const WindowContainer: React.FC<WindowContainerProps> = ({ title, onClose, onMinimize, onFocus, isActive, children }) => {
  return (
    <div 
      className={`flex flex-col w-full h-full glass-dark rounded-xl overflow-hidden shadow-2xl transition-all duration-200 border ${isActive ? 'border-blue-500/50 shadow-blue-500/10' : 'border-white/10'}`}
      onClick={onFocus}
    >
      <div className={`h-10 flex items-center justify-between px-4 border-b ${isActive ? 'bg-white/5 border-white/10' : 'bg-transparent border-white/5'}`}>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-blue-500" />
          <span className="text-sm font-medium text-slate-300">{title}</span>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={(e) => { e.stopPropagation(); onMinimize(); }} className="hover:text-white text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M5 12h14" /></svg>
          </button>
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:text-red-500 text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18 6L6 18M6 6l12 12" /></svg>
          </button>
        </div>
      </div>
      <div className="flex-1 overflow-auto bg-slate-900/40">
        {children}
      </div>
    </div>
  );
}

export default App;

import React from 'react';
import { AppId } from '../types';

interface DesktopProps {
