}

const Desktop: React.FC<DesktopProps> = ({ openApp }) => {
  const apps: { id: AppId; name: string; icon: React.ReactNode; color: string }[] = [
    { 
        id: 'minima-node', 
        name: 'Minima Node', 
        color: 'bg-blue-600',
        icon: <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 003 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z"/><path d="M12 22v-10"/><path d="M12 12L3 7"/><path d="M12 12l9-5"/></svg>
    },
    { 
        id: 'system-monitor', 
        name: 'Stats', 
        color: 'bg-emerald-600',
        icon: <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
    },
    { 
        id: 'terminal', 
        name: 'Terminal', 
        color: 'bg-slate-700',
        icon: <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 17l6-6-6-6M12 19h8"/></svg>
    },
    { 
        id: 'ai-assistant', 
        name: 'PiNet AI', 
        color: 'bg-purple-600',
        icon: <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>
    },
    { 
        id: 'wallet', 
        name: 'Wallet', 
        color: 'bg-amber-600',
        icon: <svg className="w-8 h-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 12V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2h14a2 2 0 002-2v-3.33M21 12H12"/></svg>
    },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-6 w-fit h-fit z-10">
