              // Standard single click for touch devices
              if (window.matchMedia('(pointer: coarse)').matches) openApp(app.id);
          }}
          className="group flex flex-col items-center gap-2 p-4 rounded-xl hover:bg-white/5 transition-all outline-none"
        >
          <div className={`${app.color} p-4 rounded-2xl shadow-lg app-icon-shadow group-hover:scale-105 group-active:scale-95 transition-transform`}>
            {app.icon}
          </div>
          <span className="text-xs font-medium text-slate-300 drop-shadow-md group-hover:text-white">{app.name}</span>
        </button>
      ))}
    </div>
  );
};

export default Desktop;

import React, { useState, useEffect } from 'react';
import { NodeStats, SystemStats } from '../types';

interface TopBarProps {
  nodeStats: NodeStats;
  systemStats: SystemStats;
}

const TopBar: React.FC<TopBarProps> = ({ nodeStats, systemStats }) => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <header className="h-10 fixed top-0 left-0 right-0 glass-dark z-50 flex items-center justify-between px-4 border-b border-white/5">
      <div className="flex items-center gap-6">
        <div className="flex items-center gap-2">
          <div className="w-5 h-5 bg-blue-600 rounded flex items-center justify-center">
            <span className="text-[10px] font-bold">M</span>
          </div>
          <span className="text-xs font-bold tracking-tight">PiNet <span className="text-blue-500 font-normal">OS</span></span>
        </div>

        <div className="hidden md:flex items-center gap-4 text-[10px] font-medium text-slate-400">
            <div className="flex items-center gap-1.5">
                <div className={`w-1.5 h-1.5 rounded-full ${nodeStats.status === 'Synced' ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`} />
                <span>Node: {nodeStats.status}</span>
            </div>
            <div className="w-px h-3 bg-white/10" />
            <span>Peers: {nodeStats.peers}</span>
            <div className="w-px h-3 bg-white/10" />
            <span>H: {nodeStats.blockHeight.toLocaleString()}</span>
        </div>
      </div>

      <div className="flex items-center gap-4 text-xs font-medium">
        <div className="hidden sm:flex items-center gap-4 text-slate-400 text-[10px]">
          <div className="flex items-center gap-1.5">
            <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg>
            <span>{Math.round(systemStats.cpu)}%</span>
          </div>
          <div className="flex items-center gap-1.5">
            <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 12h20M2 7h20M2 17h20"/></svg>
            <span>{systemStats.temp}°C</span>
          </div>
        </div>
        <div className="flex items-center gap-2 text-slate-300">
          <span>{time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          <span className="hidden xs:inline opacity-50 text-[10px]">|</span>
          <span className="hidden xs:inline">{time.toLocaleDateString([], { month: 'short', day: 'numeric' })}</span>
        </div>
      </div>
    </header>
  );
};

export default TopBar;

import React from 'react';
import { AppId, WindowState } from '../types';

interface TaskbarProps {
  windows: WindowState[];
  activeId: AppId;
  onAppClick: (id: AppId) => void;
}

const Taskbar: React.FC<TaskbarProps> = ({ windows, activeId, onAppClick }) => {
