const StatCard = ({ title, value, icon }: { title: string; value: string; icon: React.ReactNode }) => (
  <div className="p-4 rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 transition-colors">
    <div className="text-slate-400 mb-2">{icon}</div>
    <div className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">{title}</div>
    <div className="text-xl font-bold text-white mt-1">{value}</div>
  </div>
);

const MiniDappItem = ({ name, description, color }: { name: string; description: string; color: string }) => (
  <div className={`p-4 rounded-xl ${color} border border-white/5 cursor-pointer hover:scale-[1.02] transition-transform`}>
    <div className="font-bold">{name}</div>
    <div className="text-[10px] opacity-70 mt-1">{description}</div>
  </div>
);

const HealthIndicator = ({ label, percentage, color }: { label: string; percentage: number; color: string }) => (
  <div className="space-y-1">
    <div className="flex justify-between text-[10px] font-medium text-slate-400">
      <span>{label}</span>
      <span>{percentage}%</span>
    </div>
    <div className="h-1.5 w-full bg-slate-700 rounded-full overflow-hidden">
      <div className={`h-full ${color}`} style={{ width: `${percentage}%` }} />
    </div>
  </div>
