  status: 'online' | 'offline' | 'processing';
  metrics: {
    cpu: number;
    ram: number;
    temp: number;
    npu?: number;
    iops?: number;
    env?: { temp: number; humidity: number; pressure: number };
  };
}

export interface M402Session {
  sessionId: string;
  ratePerSecond: number;
  totalBurned: number;
  isActive: boolean;
  startTime?: number;
}

export interface MaximaContact {
  name: string;
