import React, { useState, useEffect } from 'react';
import { ClusterNode, M402Session } from '../../types';
import { MinimaService } from '../../services/minimaService';

interface DePAiExecutorProps {
  nodes: ClusterNode[];
}

const DePAiExecutor: React.FC<DePAiExecutorProps> = ({ nodes }) => {
  const [session, setSession] = useState<M402Session | null>(null);
  const [activeTask, setActiveTask] = useState<string | null>(null);
  const [output, setOutput] = useState<string[]>(["DePAI Shell ready.", "Waiting for agent deployment..."]);

  const tasks = [
    { id: 'env-analyze', name: 'Environment Analysis Agent', description: 'Combines Sense Hat & NPU to detect anomalies.', rate: 0.01 },
    { id: 'local-llm', name: 'Local Llama-3-Pi Inference', description: 'Quantized LLM running on NPU Hat.', rate: 0.05 },
    { id: 'data-shard', name: 'SSD Decentralized Sharder', description: 'Optimizes SSD NVMe for global persistence.', rate: 0.02 },
  ];

  const startTask = async (task: typeof tasks[0]) => {
    setActiveTask(task.name);
    setOutput(prev => [...prev, `Deploying ${task.name}...`, `Establishing M.402 Payment Stream at ${task.rate} MIN/sec...`]);

    const sessionId = await MinimaService.initiateM402Stream(task.rate);
    setSession({ sessionId, ratePerSecond: task.rate, totalBurned: 0, isActive: true, startTime: Date.now() });

    setOutput(prev => [...prev, `Handshaking with Pi-Alpha NPU core...`, `Agentic session established: ${sessionId}`]);
  };

  const stopTask = async () => {
    if (session) {
      await MinimaService.stopM402Stream(session.sessionId);
      setOutput(prev => [...prev, `M.402 Stream Terminated. Session: ${session.sessionId}`, `Total resource cost: ${session.totalBurned.toFixed(4)} MIN`]);
      setSession(null);
      setActiveTask(null);
    }
  };

  // Simulate payment burner
  useEffect(() => {
    if (session && session.isActive) {
      const timer = setInterval(() => {
        setSession(prev => prev ? {
            ...prev,
            totalBurned: prev.totalBurned + prev.ratePerSecond
        } : null);

        // Random agent logs
        if (Math.random() > 0.7) {
            setOutput(prev => [...prev.slice(-10), `[AGENT] Processing shard block ${Math.floor(Math.random() * 99999)}... OK`]);
        }
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [session]);

  return (
    <div className="flex h-full">
      <div className="w-80 border-r border-white/5 p-6 flex flex-col gap-6">
        <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Available Agents</h3>
        <div className="space-y-3">
          {tasks.map(t => (
            <button
              key={t.id}
              disabled={!!activeTask}
              onClick={() => startTask(t)}
              className={`w-full p-4 rounded-xl border text-left transition-all ${activeTask === t.name ? 'bg-indigo-600/20 border-indigo-400' : 'bg-white/5 border-white/5 hover:border-white/20'}`}
            >
              <div className="text-sm font-bold text-white">{t.name}</div>
              <div className="text-[10px] text-slate-400 mt-1">{t.description}</div>
              <div className="mt-3 flex justify-between items-center">
                <span className="text-[10px] font-mono text-emerald-400">{t.rate} MIN/s</span>
                {!activeTask && <span className="text-[9px] bg-indigo-500 text-white px-2 py-0.5 rounded uppercase">Deploy</span>}
              </div>
            </button>
          ))}
        </div>

        {session && (
          <div className="mt-auto p-4 rounded-xl bg-indigo-600/10 border border-indigo-500/30">
             <div className="text-[10px] font-bold text-indigo-400 uppercase mb-2">Live M.402 Stream</div>
             <div className="text-2xl font-mono text-white">{session.totalBurned.toFixed(4)} <span className="text-xs font-normal opacity-50">MIN</span></div>
             <button 
                onClick={stopTask}
                className="w-full mt-4 py-2 bg-rose-600 hover:bg-rose-500 text-white text-xs font-bold rounded-lg transition-colors"
             >
                Kill Agent Session
             </button>
          </div>
        )}
      </div>

      <div className="flex-1 flex flex-col bg-black/30">
        <div className="p-4 border-b border-white/5 flex justify-between items-center">
            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">Agent Execution Log</div>
            {activeTask && (
                <div className="flex items-center gap-2">
                    <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping" />
                    <span className="text-[10px] text-emerald-400 font-bold uppercase">Executing: {activeTask}</span>
                </div>
            )}
        </div>
        <div className="flex-1 p-6 font-mono text-[11px] text-slate-300 overflow-auto">
            {output.map((line, i) => (
                <div key={i} className="mb-1">
                    <span className="text-slate-600 mr-2">[{new Date().toLocaleTimeString()}]</span>
                    {line}
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

