import React, { useState, useRef, useEffect } from 'react';
import { getAiResponse } from '../../services/geminiService';

interface AiAssistantAppProps {
  context: any;
}

const AiAssistantApp: React.FC<AiAssistantAppProps> = ({ context }) => {
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; content: string }[]>([
    { role: 'assistant', content: "Hello! I'm your PiNet OS intelligence. I'm connected to your 3-node cluster and monitoring M.402 payment streams. How can I help today?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userText = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsLoading(true);

    const response = await getAiResponse(userText, context);
    setMessages(prev => [...prev, { role: 'assistant', content: response || "I couldn't process that request." }]);
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 backdrop-blur-sm relative">
      {/* Context Badge */}
      <div className="absolute top-2 right-4 flex items-center gap-2 px-3 py-1 bg-blue-500/10 border border-blue-500/20 rounded-full z-10 pointer-events-none">
        <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
        <span className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Cluster Context Sync Active</span>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto p-6 pt-12 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-2xl text-sm ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-br-none' 
                : 'glass border border-white/5 text-slate-300 rounded-bl-none shadow-xl'
            }`}>
              {m.content}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
