import { GoogleGenAI, Type, Modality } from "@google/genai";

export const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getAiResponse = async (prompt: string, options: { 
  context?: any, 
  mode: 'fast' | 'complex' | 'thinking' | 'maps',
  media?: { data: string, mimeType: string }[]
}) => {
  const ai = getAiClient();
  let model = 'gemini-2.5-flash-lite-latest';
  const config: any = {
    temperature: 0.7,
    systemInstruction: `You are PiNet AI, the master intelligence for a 3-node Raspberry Pi 5 cluster.
    Stack Composition:
    - Node 1 (Pi-Alpha): 16GB RAM, AI NPU Hat (Master Control).
    - Node 2 (Pi-Beta): 16GB RAM, Sense Hat (Environmental Monitoring).
    - Node 3 (Pi-Gamma): 16GB RAM, SSD NVMe Hat (Storage & Persistence).

    Current Telemetry Context: ${JSON.stringify(options.context || {})}.

    Guidelines:
    - If in 'thinking' mode, provide deep architectural reasoning.
    - If 'maps' mode is used, focus on geographic distribution of peers or hardware logistics.
    - Be technical, efficient, and enforce M.402 payment protocol awareness.`
  };

  if (options.mode === 'complex' || options.media?.length) {
    model = 'gemini-3-pro-preview';
  } else if (options.mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (options.mode === 'maps') {
    model = 'gemini-2.5-flash-latest';
    config.tools = [{ googleMaps: {} }];
    // Request location if available
    try {
      const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: pos.coords.latitude, longitude: pos.coords.longitude }
        }
      };
    } catch (e) { /* ignore geolocation errors */ }
  }

  try {
    const parts: any[] = [{ text: prompt }];
    if (options.media) {
      options.media.forEach(m => {
        parts.push({ inlineData: m });
      });
    }

    const response = await ai.models.generateContent({
      model,
      contents: [{ parts }],
      config
    });

    let text = response.text || "";

    // Extract grounding URLs if using maps
    if (options.mode === 'maps' && response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      const links = response.candidates[0].groundingMetadata.groundingChunks
        .map((chunk: any) => chunk.maps?.uri || chunk.web?.uri)
        .filter(Boolean);
      if (links.length > 0) {
        text += "\n\n**Reference Links:**\n" + links.map((l: string) => `- [View on Maps](${l})`).join('\n');
      }
    }

    return text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    if (JSON.stringify(error).includes("Requested entity was not found")) {
      return "ERROR_KEY_REQUIRED";
    }
    return "Neural uplink failed. Ensure your API_KEY is valid and network connectivity is active.";
  }
};

export const generateVeoVideo = async (prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') => {
  const ai = getAiClient();
  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: `Web3PiOS Cluster Visualization: ${prompt}`,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await ai.operations.getVideosOperation({ operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error) {
    console.error("Veo Generation Error:", error);
    return null;
  }
};

