import { GoogleGenAI, Type, Modality } from "@google/genai";

export const getAiClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

/**
 * Advanced Multi-Modal AI Interface
 */
export const getAiResponse = async (prompt: string, options: { 
  context?: any, 
  mode: 'fast' | 'complex' | 'thinking' | 'maps',
  media?: { data: string, mimeType: string }[]
}) => {
  const ai = getAiClient();
  let model = 'gemini-2.5-flash-lite-latest'; // Default fast model
  const config: any = {
    temperature: 0.7,
    systemInstruction: `You are PiNet AI, the master intelligence for Web3PiOS. 
    Operating on a 3-node Raspberry Pi 5 cluster.

    Current Telemetry Context: ${JSON.stringify(options.context || {})}.

    Capabilities:
    1. Multi-Pi Cluster Provisioning (Master, Sense, Storage nodes).
    2. M.402 Agentic Payment Protocol awareness.
    3. Hardware Hat management (NPU, Sense, NVMe).
    4. Vision-based hardware diagnostics.
    5. Thinking Mode: Advanced architectural reasoning for complex queries.`
  };

  // Model Selection Logic
  if (options.mode === 'complex' || options.media?.length) {
    model = 'gemini-3-pro-preview';
  } else if (options.mode === 'thinking') {
    model = 'gemini-3-pro-preview';
    config.thinkingConfig = { thinkingBudget: 32768 };
  } else if (options.mode === 'maps') {
    model = 'gemini-2.5-flash-latest';
    config.tools = [{ googleMaps: {} }];
    try {
      const pos = await new Promise<GeolocationPosition>((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));
      config.toolConfig = {
        retrievalConfig: {
          latLng: { latitude: pos.coords.latitude, longitude: pos.coords.longitude }
        }
      };
    } catch (e) { /* Fallback if geo blocked */ }
  } else if (options.mode === 'fast') {
    model = 'gemini-2.5-flash-lite-latest';
  }

  try {
    const parts: any[] = [{ text: prompt }];
    if (options.media) {
      options.media.forEach(m => {
        parts.push({ inlineData: m });
      });
    }

    const response = await ai.models.generateContent({
      model,
      contents: [{ parts }],
      config
    });

    let text = response.text || "";

    if (options.mode === 'maps' && response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      const links = response.candidates[0].groundingMetadata.groundingChunks
        .map((chunk: any) => chunk.maps?.uri || chunk.web?.uri)
        .filter(Boolean);
      if (links.length > 0) {
        text += "\n\n**Grounding Sources:**\n" + links.map((l: string) => `- [Open Map Resource](${l})`).join('\n');
      }
    }

    return text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Neural uplink timeout. Check your project API configuration.";
  }
};

/**
 * High-Quality Image Generation (Gemini 3 Pro Image / "Nano Banana Pro")
 */
export const generateClusterAssets = async (prompt: string) => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: `High-fidelity Web3PiOS interface mockup: ${prompt}` }] },
      config: {
        imageConfig: { aspectRatio: "16:9", imageSize: "1K" }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Generation Error:", error);
    return null;
  }
};

/**
 * Veo 3 Video Generation
 */
export const generateClusterVideo = async (prompt: string, orientation: '16:9' | '9:16' = '16:9') => {
  const ai = getAiClient();
  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: `Web3PiOS futuristic UI transition: ${prompt}`,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: orientation
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 8000));
      operation = await ai.operations.getVideosOperation({ operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error) {
    console.error("Veo Video Error:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { generateClusterAssets, generateClusterVideo } from '../../services/geminiService';

const VisualAssetStudio: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [assets, setAssets] = useState<{ type: 'image' | 'video', url: string, prompt: string }[]>([]);
  const [orientation, setOrientation] = useState<'16:9' | '9:16'>('16:9');

  const handleGenerate = async (type: 'image' | 'video') => {
    if (!prompt.trim() || isGenerating) return;

    // Check key
    if (window.aistudio && !(await window.aistudio.hasSelectedApiKey())) {
      await window.aistudio.openSelectKey();
    }

    setIsGenerating(true);
    let url = null;

    if (type === 'image') {
      url = await generateClusterAssets(prompt);
    } else {
      url = await generateClusterVideo(prompt, orientation);
    }

    if (url) {
      setAssets(prev => [{ type, url, prompt }, ...prev]);
      setPrompt('');
    }
    setIsGenerating(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-950/80">
      <div className="p-6 border-b border-white/10 flex items-center justify-between bg-black/40">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-pink-600 rounded-2xl flex items-center justify-center shadow-xl shadow-pink-500/20">
            <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2-2v12a2 2 0 002 2z"/></svg>
