      const reader = new FileReader();
      reader.onload = (ev) => {
        const base64 = (ev.target?.result as string).split(',')[1];
        setMediaToUpload(prev => [...prev, { 
          data: base64, 
          mimeType: file.type,
          preview: URL.createObjectURL(file)
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleVeoGen = async () => {
    if (!input.trim() || isLoading) return;
    if (provider === 'airllm') {
      setMessages(prev => [...prev, { role: 'assistant', content: "Video generation is only supported on Gemini cloud providers via the Beta gateway." }]);
      return;
    }

    if (window.aistudio && !(await window.aistudio.hasSelectedApiKey())) {
      setMessages(prev => [...prev, { role: 'assistant', content: "Veo generation requires a paid API key for the Beta node bridge." }]);
      return;
    }

    const prompt = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: `Generate video: ${prompt}` }]);
    setIsLoading(true);

    const videoUrl = await generateVeoVideo(prompt);
    if (videoUrl) {
      setMessages(prev => [...prev, { role: 'assistant', content: videoUrl, type: 'video' }]);
    } else {
      setMessages(prev => [...prev, { role: 'assistant', content: "Gateway Error: Failed to generate video. Ensure project billing is enabled." }]);
    }
    setIsLoading(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && mediaToUpload.length === 0) || isLoading) return;

    const userText = input.trim();
    setInput('');
    const currentMedia = [...mediaToUpload];
    setMediaToUpload([]);

    setMessages(prev => [...prev, { role: 'user', content: userText || "Analyzing cluster telemetry..." }]);
    setIsLoading(true);

    const response = await getAiResponse(userText, { 
      context, 
      mode, 
      provider,
      localEndpoint: localUrl,
      media: currentMedia.map(m => ({ data: m.data, mimeType: m.mimeType }))
    });

    if (response === "ERROR_KEY_REQUIRED") {
        setMessages(prev => [...prev, { role: 'assistant', content: "Beta Bridge: Advanced reasoning requires a paid API key in settings." }]);
    } else {
        setMessages(prev => [...prev, { role: 'assistant', content: response || "Gateway Timeout: Neural uplink was not established." }]);
    }
    setIsLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 backdrop-blur-sm relative">
      <div className="p-4 border-b border-white/5 flex flex-wrap gap-4 items-center bg-black/20">
        <div className="flex bg-white/5 rounded-lg p-1 border border-white/10 items-center gap-2">
            <span className="text-[9px] font-bold text-slate-500 uppercase px-2">Gateway</span>
            <button 
                onClick={() => setProvider('gemini')}
                className={`px-3 py-1.5 rounded-md text-[10px] font-bold uppercase transition-all ${provider === 'gemini' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
                Gemini Cloud
            </button>
            <button 
                onClick={() => setProvider('airllm')}
                className={`px-3 py-1.5 rounded-md text-[10px] font-bold uppercase transition-all ${provider === 'airllm' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
                AirLLM Local
            </button>
        </div>

        {provider === 'gemini' && (
          <div className="flex bg-white/5 rounded-lg p-1 border border-white/10 items-center gap-1">
             <span className="text-[9px] font-bold text-slate-500 uppercase px-2">NPU Mode</span>
            {(['fast', 'complex', 'thinking', 'maps'] as Mode[]).map(m => (
              <button
                key={m}
                onClick={() => setMode(m)}
                className={`px-3 py-1.5 rounded-md text-[10px] font-bold uppercase transition-all ${
                  mode === m ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
                }`}
              >
                {m}
              </button>
            ))}
          </div>
        )}

        {provider === 'airllm' && (
            <div className="flex-1 max-w-xs relative">
                <input 
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-1.5 text-[10px] font-mono text-emerald-400 focus:outline-none focus:border-emerald-500/50"
                    placeholder="Local Endpoint..."
                    value={localUrl}
                    onChange={e => setLocalUrl(e.target.value)}
                />
                <div className="absolute right-3 top-1/2 -translate-y-1/2 w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]" />
            </div>
        )}

        {window.aistudio && provider === 'gemini' && (
           <button 
             onClick={() => window.aistudio.openSelectKey()}
             className="ml-auto px-3 py-1.5 bg-pink-600/20 border border-pink-500/40 text-pink-400 rounded-md text-[9px] font-bold uppercase tracking-widest hover:bg-pink-600 hover:text-white transition-all"
           >
             Beta Bridge Key
           </button>
        )}
      </div>

      <div ref={scrollRef} className="flex-1 overflow-auto p-6 space-y-6">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl text-sm ${
              m.role === 'user' 
                ? 'bg-blue-600 text-white rounded-br-none' 
                : 'glass border border-white/5 text-slate-300 rounded-bl-none shadow-xl'
            }`}>
              {m.type === 'video' ? (
                <div className="space-y-2">
                  <video src={m.content} controls className="w-full rounded-lg shadow-2xl border border-white/10" />
                  <p className="text-[10px] text-slate-400 italic">Beta Node Render: Neural UI Transition</p>
                </div>
              ) : m.content.startsWith('http') && m.type === 'image' ? (
                <img src={m.content} className="max-w-full rounded-lg" />
              ) : (
                <div className="prose prose-invert prose-sm max-w-none">
                   {m.content.split('\n').map((line, li) => <p key={li}>{line}</p>)}
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="glass border border-white/5 p-4 rounded-2xl rounded-bl-none flex flex-col gap-3">
              <div className="flex gap-1.5">
                <div className={`w-2 h-2 ${provider === 'airllm' ? 'bg-emerald-500' : 'bg-purple-500'} rounded-full animate-bounce`} />
                <div className={`w-2 h-2 ${provider === 'airllm' ? 'bg-emerald-500' : 'bg-purple-500'} rounded-full animate-bounce [animation-delay:-0.15s]`} />
                <div className={`w-2 h-2 ${provider === 'airllm' ? 'bg-emerald-500' : 'bg-purple-500'} rounded-full animate-bounce [animation-delay:-0.3s]`} />
              </div>
              <span className={`text-[9px] font-mono ${provider === 'airllm' ? 'text-emerald-400' : 'text-purple-400'} animate-pulse tracking-widest uppercase`}>
                  {provider === 'airllm' ? 'Beta Node: Sharding Local Inference...' : 'Beta Node: Routing to Gemini Cloud Gateway...'}
              </span>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t border-white/5 space-y-4">
        {mediaToUpload.length > 0 && (
          <div className="flex gap-2 p-2 bg-white/5 rounded-xl border border-white/10 overflow-x-auto">
            {mediaToUpload.map((m, i) => (
              <div key={i} className="relative group shrink-0">
                <img src={m.preview} className="w-16 h-16 object-cover rounded-lg border border-white/20" />
                <button 
                  type="button"
                  onClick={() => setMediaToUpload(prev => prev.filter((_, idx) => idx !== i))}
                  className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12"/></svg>
                </button>
              </div>
            ))}
          </div>
        )}

        <div className="flex gap-2">
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*,video/*" 
              multiple 
              onChange={handleFileUpload} 
            />
            <button 
              type="button"
              onClick={() => fileInputRef.current?.click()}
              className="p-3 bg-white/5 border border-white/10 text-slate-400 rounded-xl hover:bg-white/10 transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2-2v12a2 2 0 002 2z"/></svg>
            </button>

            <div className="relative flex-1">
                <input
                className={`w-full glass-dark border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:outline-none transition-colors pr-12 ${provider === 'airllm' ? 'focus:border-emerald-500/50' : 'focus:border-purple-500/50'}`}
                placeholder={provider === 'airllm' ? "Routing local inference via Beta NPU..." : "Routing cloud request via Beta Bridge..."}
                value={input}
                onChange={e => setInput(e.target.value)}
                />
                {provider === 'gemini' && (
                    <button 
                      type="button"
                      onClick={handleVeoGen}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-pink-500 hover:text-pink-400 transition-colors p-1"
                      title="Beta Node Render"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"/></svg>
                    </button>
                )}
            </div>

            <button 
              type="submit"
              disabled={isLoading}
              className={`p-3 disabled:opacity-50 text-white rounded-xl transition-all active:scale-95 shadow-lg flex items-center gap-2 ${provider === 'airllm' ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-purple-600 hover:bg-purple-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
            </button>
        </div>
      </form>
    </div>
  );
};

export default AiAssistantApp;

import React, { useState, useEffect } from 'react';
import Desktop from './components/Desktop';
import Taskbar from './components/Taskbar';
import TopBar from './components/TopBar';
import SetupWizard from './components/apps/SetupWizard';
import { AppId, WindowState, NodeStats, SystemStats, ClusterNode } from './types';
import MinimaNodeApp from './components/apps/MinimaNodeApp';
import SystemMonitorApp from './components/apps/SystemMonitorApp';
import TerminalApp from './components/apps/TerminalApp';
import AiAssistantApp from './components/apps/AiAssistantApp';
import WalletApp from './components/apps/WalletApp';
import MaximaMessengerApp from './components/apps/MaximaMessengerApp';
import ClusterManagerApp from './components/apps/ClusterManagerApp';
import DePAiExecutor from './components/apps/DePAiExecutor';
import ImagerUtility from './components/apps/ImagerUtility';

const App: React.FC = () => {
  const [isSetupComplete, setIsSetupComplete] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'minima-node', title: 'Minima Node', isOpen: true, isMinimized: false, zIndex: 10 },
    { id: 'system-monitor', title: 'System Monitor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'terminal', title: 'PiNet Shell', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'ai-assistant', title: 'PiNet AI Assistant', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'wallet', title: 'Web3 Wallet', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'maxima-messenger', title: 'Maxima Messenger', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'cluster-manager', title: 'Cluster Hub', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'depai-executor', title: 'DePAI Executor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'imager-utility', title: 'Pi Imager Config', isOpen: false, isMinimized: false, zIndex: 1 },
  ]);

  const [activeId, setActiveId] = useState<AppId>('minima-node');
  const [nodeStats, setNodeStats] = useState<NodeStats>({
    blockHeight: 1245091,
    peers: 14,
    status: 'Synced',
    uptime: '14d 05h 22m',
    version: '1.0.35'
  });

  const [clusterNodes, setClusterNodes] = useState<ClusterNode[]>([
    { id: 'n1', name: 'Pi-Alpha (NVMe Storage Hub)', ip: '192.168.1.10', hat: 'SSD_NVME', status: 'online', metrics: { cpu: 12, ram: 2.1, temp: 45, iops: 12500 } },
    { id: 'n2', name: 'Pi-Beta (Intelligence Hub)', ip: '192.168.1.11', hat: 'AI_NPU', status: 'online', metrics: { cpu: 8, ram: 1.4, temp: 42, npu: 15 } },
    { id: 'n3', name: 'Pi-Gamma (Sensory Node)', ip: '192.168.1.12', hat: 'SENSE', status: 'online', metrics: { cpu: 15, ram: 3.2, temp: 48, env: { temp: 22.4, humidity: 45, pressure: 1012 } } },
  ]);

  const [sysStats, setSysStats] = useState<SystemStats>({
    cpu: 24, ram: 45, temp: 42, disk: 12
  });

  useEffect(() => {
    const interval = setInterval(() => {
      setSysStats(prev => ({
        cpu: Math.max(10, Math.min(95, prev.cpu + (Math.random() * 10 - 5))),
        ram: Math.max(40, Math.min(60, prev.ram + (Math.random() * 2 - 1))),
        temp: Math.max(38, Math.min(65, prev.temp + (Math.random() * 4 - 2))),
        disk: prev.disk
      }));

      setClusterNodes(prev => prev.map(node => ({
        ...node,
        metrics: {
          ...node.metrics,
          cpu: Math.random() * 30 + 5,
          temp: Math.random() * 10 + 40,
          npu: node.hat === 'AI_NPU' ? Math.random() * 100 : undefined,
          iops: node.hat === 'SSD_NVME' ? Math.random() * 8000 + 12000 : undefined,
        }
      })));

      setNodeStats(prev => ({ ...prev, blockHeight: prev.blockHeight + 1 }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const openApp = (id: AppId) => {
    setWindows(prev => prev.map(w => {
      if (w.id === id) {
        return { ...w, isOpen: true, isMinimized: false, zIndex: Math.max(...prev.map(x => x.zIndex)) + 1 };
      }
      return w;
    }));
    setActiveId(id);
  };

  const closeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const minimizeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
  };

  const bringToFront = (id: AppId) => {
    const maxZ = Math.max(...windows.map(w => w.zIndex));
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: maxZ + 1, isMinimized: false } : w));
    setActiveId(id);
  };

  if (!isSetupComplete) {
    return <SetupWizard onComplete={() => setIsSetupComplete(true)} />;
  }

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-slate-950 flex flex-col font-sans select-none">
      <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_50%_50%,rgba(197,26,74,0.1),rgba(0,0,0,0))]" />
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />

      <TopBar nodeStats={nodeStats} systemStats={sysStats} />

      <main className="flex-1 relative overflow-hidden p-6 mt-10 mb-16">
        <Desktop openApp={openApp} />

        {windows.map(win => {
          if (!win.isOpen) return null;

          return (
            <div 
              key={win.id}
              style={{ zIndex: win.zIndex, display: win.isMinimized ? 'none' : 'block' }}
              className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-5xl h-[75vh]"
            >
              <WindowContainer 
                title={win.title} 
                onClose={() => closeApp(win.id)}
                onMinimize={() => minimizeApp(win.id)}
                onFocus={() => bringToFront(win.id)}
                isActive={activeId === win.id}
              >
                {win.id === 'minima-node' && <MinimaNodeApp stats={nodeStats} />}
                {win.id === 'system-monitor' && <SystemMonitorApp stats={sysStats} />}
                {win.id === 'terminal' && <TerminalApp />}
                {win.id === 'ai-assistant' && (
                  <AiAssistantApp 
                    context={{ 
                      node: nodeStats, 
                      cluster: clusterNodes, 
                      telemetry: sysStats,
                      timestamp: new Date().toISOString()
                    }} 
                  />
                )}
                {win.id === 'wallet' && <WalletApp />}
                {win.id === 'maxima-messenger' && <MaximaMessengerApp />}
                {win.id === 'cluster-manager' && <ClusterManagerApp nodes={clusterNodes} />}
                {win.id === 'depai-executor' && <DePAiExecutor nodes={clusterNodes} />}
                {win.id === 'imager-utility' && <ImagerUtility />}
              </WindowContainer>
            </div>
          );
        })}
      </main>

      <Taskbar 
        windows={windows} 
        activeId={activeId} 
        onAppClick={(id) => {
          const win = windows.find(w => w.id === id);
          if (win?.isMinimized || !win?.isOpen) {
            openApp(id);
          } else if (activeId === id) {
            minimizeApp(id);
          } else {
            bringToFront(id);
          }
        }} 
      />
    </div>
  );
};

interface WindowContainerProps {
  title: string;
  onClose: () => void;
  onMinimize: () => void;
  onFocus: () => void;
  isActive: boolean;
  children: React.ReactNode;
}

const WindowContainer: React.FC<WindowContainerProps> = ({ title, onClose, onMinimize, onFocus, isActive, children }) => {
  return (
    <div 
      className={`flex flex-col w-full h-full glass-dark rounded-2xl overflow-hidden shadow-2xl transition-all duration-200 border-2 ${isActive ? 'border-pink-500/40 shadow-pink-500/10' : 'border-white/10'}`}
      onClick={onFocus}
    >
      <div className={`h-11 flex items-center justify-between px-5 border-b ${isActive ? 'bg-white/10 border-white/20' : 'bg-transparent border-white/5'}`}>
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isActive ? 'bg-pink-500 animate-pulse' : 'bg-slate-600'}`} />
          <span className="text-sm font-semibold text-slate-200 tracking-wide uppercase">{title}</span>
        </div>
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); onMinimize(); }} className="hover:text-white text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14" /></svg>
          </button>
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:text-red-500 text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M18 6L6 18M6 6l12 12" /></svg>
          </button>
        </div>
      </div>
      <div className="flex-1 overflow-auto bg-slate-900/60">
        {children}
      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';

type LineType = 'header' | 'prompt' | 'info' | 'success' | 'error' | 'command' | 'code' | 'warning';

interface TerminalLine {
  text: string;
  type: LineType;
}

const COMMANDS = [
  'help', 
  'status', 
  'peers', 
  'balance', 
  'clear', 
  'reboot', 
  'cluster list', 
  'm402 status',
  'maxima info',
  'node version'
];

const TerminalApp: React.FC = () => {
  const [history, setHistory] = useState<TerminalLine[]>([
    { text: 'PiNet Web3 OS Shell [Version 1.0.35]', type: 'header' },
    { text: '(c) 2024 Minima Global. Decentralized Node Environment.', type: 'info' },
    { text: '', type: 'info' },
    { text: 'Welcome, Agent. Type "help" to list available protocols.', type: 'info' },
    { text: '', type: 'info' }
  ]);
  const [input, setInput] = useState('');
  const [suggestion, setSuggestion] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history]);

  useEffect(() => {
    const trimmedInput = input.trim().toLowerCase();
    if (trimmedInput) {
      const match = COMMANDS.find(cmd => cmd.startsWith(trimmedInput));
      if (match && match !== trimmedInput) {
        // Only suggest if the match is longer than input
        setSuggestion(match.slice(input.length));
      } else {
        setSuggestion('');
      }
    } else {
      setSuggestion('');
    }
  }, [input]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Tab' && suggestion) {
      e.preventDefault();
      setInput(input + suggestion);
      setSuggestion('');
    }
  };

  const handleCommand = (e: React.FormEvent) => {
    e.preventDefault();
    const rawCmd = input.trim();
    const cmd = rawCmd.toLowerCase();
    if (!cmd) return;

    const newHistory: TerminalLine[] = [{ text: `pinet@raspberrypi:~$ ${rawCmd}`, type: 'prompt' }];

    switch (cmd) {
      case 'help':
        newHistory.push(
          { text: 'SYSTEM COMMANDS:', type: 'header' },
          { text: '  status         - Core node health & sync state', type: 'info' },
          { text: '  peers          - Global P2P connection topology', type: 'info' },
          { text: '  balance        - M.402 Wallet & Token metrics', type: 'info' },
          { text: '  clear          - Flush shell buffer', type: 'info' },
          { text: '  reboot         - Thermal-safe cluster restart', type: 'info' },
          { text: '  cluster list   - Show sharded Pi nodes', type: 'info' },
          { text: '  m402 status    - Active agentic billing streams', type: 'info' }
        );
        break;
      case 'status':
        newHistory.push(
          { text: 'NODE IDENTIFIER: 0x7471...F2E9', type: 'info' },
          { text: 'NETWORK STATUS: [ ONLINE ]', type: 'success' },
          { text: 'SYNC PROGRESS: 100.00% (Block 1,245,092)', type: 'success' },
          { text: 'PROTOCOL: Minima Mainnet v1.0.35', type: 'info' }
        );
        break;
      case 'peers':
        newHistory.push(
          { text: 'DISCOVERING PEERS...', type: 'info' },
          { text: 'CONNECTED: 14 Nodes', type: 'success' },
          { text: 'LATENCY: 42ms (Average)', type: 'info' },
          { text: 'TOPOLOGY: Sharded P2P Mesh', type: 'warning' }
        );
        break;
      case 'balance':
        newHistory.push(
          { text: 'AVAILABLE: 1,250.45 MIN', type: 'success' },
          { text: 'STAKED: 5,000.00 MIN', type: 'info' },
          { text: 'M.402 BURN RATE: 0.042 MIN/hour', type: 'warning' }
        );
        break;
      case 'cluster list':
        newHistory.push(
          { text: 'ID      ROLE      STATUS    HAT', type: 'header' },
          { text: 'n1      Alpha     ONLINE    SSD_NVME', type: 'info' },
          { text: 'n2      Beta      ONLINE    AI_NPU', type: 'info' },
          { text: 'n3      Gamma     ONLINE    SENSE', type: 'info' }
        );
        break;
      case 'clear':
        setHistory([]);
        setInput('');
        return;
      case 'reboot':
        newHistory.push(
          { text: 'Initiating safe cluster shutdown...', type: 'warning' },
          { text: 'Flushing cache to NVMe...', type: 'info' },
          { text: 'Broadcast signal sent to nodes n2, n3.', type: 'info' },
          { text: 'Rebooting Kernel...', type: 'info' },
          { text: 'System back online.', type: 'success' }
        );
        break;
      case 'node version':
        newHistory.push({ text: 'PiNet Web3 OS v1.0.35-stable (aarch64)', type: 'code' });
        break;
      default:
        newHistory.push({ text: `pinet: command not found: ${rawCmd}`, type: 'error' });
    }

    setHistory(prev => [...prev, ...newHistory]);
    setInput('');
  };

  const getLineStyles = (type: LineType) => {
    switch (type) {
      case 'header': return 'text-white font-bold tracking-tight border-l-2 border-white/20 pl-2 my-1';
      case 'prompt': return 'text-blue-400 font-bold drop-shadow-[0_0_3px_rgba(96,165,250,0.5)]';
      case 'info': return 'text-slate-400';
      case 'success': return 'text-emerald-400 drop-shadow-[0_0_3px_rgba(52,211,153,0.3)]';
      case 'error': return 'text-rose-400 font-medium italic';
      case 'warning': return 'text-amber-400 italic';
      case 'code': return 'text-indigo-400 bg-indigo-500/5 px-1 rounded';
      default: return 'text-slate-300';
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#020617] font-mono text-xs sm:text-sm p-6 overflow-hidden relative">
      <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_50%_0%,rgba(59,130,246,0.05),transparent)]" />

      <div ref={scrollRef} className="flex-1 overflow-auto space-y-1 relative z-10 custom-terminal-scrollbar selection:bg-blue-500/30">
        {history.map((line, i) => (
          <div key={i} className={`whitespace-pre-wrap leading-relaxed transition-all duration-300 animate-in fade-in slide-in-from-left-2 ${getLineStyles(line.type)}`}>
            {line.text}
          </div>
        ))}
      </div>

      <form onSubmit={handleCommand} className="mt-4 flex gap-2 border-t border-white/5 pt-4 group relative z-10">
        <span className="text-blue-400 shrink-0 font-bold select-none">pinet@raspberrypi:~$</span>
        <div className="relative flex-1 min-w-0">
          <input 
            autoFocus
            onKeyDown={handleKeyDown}
            className="w-full bg-transparent border-none outline-none text-white caret-pink-500 selection:bg-pink-500/30"
            value={input}
            onChange={e => setInput(e.target.value)}
            spellCheck={false}
            autoComplete="off"
          />
          {suggestion && (
            <span className="absolute left-0 top-0 pointer-events-none text-slate-600 opacity-60 italic">
              <span className="invisible whitespace-pre">{input}</span>
              {suggestion}
            </span>
          )}
        </div>
        {suggestion && (
          <span className="hidden sm:block text-[9px] font-bold text-slate-600 uppercase tracking-tighter opacity-0 group-hover:opacity-100 transition-opacity self-center">
            [Tab]
          </span>
        )}
      </form>
    </div>
  );
};

