import Taskbar from './components/Taskbar';
import TopBar from './components/TopBar';
import SetupWizard from './components/apps/SetupWizard';
import { AppId, WindowState, NodeStats, SystemStats, ClusterNode } from './types';
import MinimaNodeApp from './components/apps/MinimaNodeApp';
import SystemMonitorApp from './components/apps/SystemMonitorApp';
import TerminalApp from './components/apps/TerminalApp';
import AiAssistantApp from './components/apps/AiAssistantApp';
import WalletApp from './components/apps/WalletApp';
import MaximaMessengerApp from './components/apps/MaximaMessengerApp';
import ClusterManagerApp from './components/apps/ClusterManagerApp';
import DePAiExecutor from './components/apps/DePAiExecutor';
import ImagerUtility from './components/apps/ImagerUtility';
import FileExplorerApp from './components/apps/FileExplorerApp';
import SettingsApp from './components/apps/SettingsApp';

const App: React.FC = () => {
  const [isSetupComplete, setIsSetupComplete] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'minima-node', title: 'Minima Node', isOpen: true, isMinimized: false, zIndex: 10 },
    { id: 'system-monitor', title: 'System Monitor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'terminal', title: 'PiNet Shell', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'ai-assistant', title: 'PiNet AI Assistant', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'wallet', title: 'Web3 Wallet', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'maxima-messenger', title: 'Maxima Messenger', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'cluster-manager', title: 'Cluster Hub', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'depai-executor', title: 'DePAI Executor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'imager-utility', title: 'Pi Imager Config', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'file-explorer', title: 'File Explorer', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'settings', title: 'System Settings', isOpen: false, isMinimized: false, zIndex: 1 },
  ]);

  const [activeId, setActiveId] = useState<AppId>('minima-node');
  const [nodeStats, setNodeStats] = useState<NodeStats>({
    blockHeight: 1245091,
    peers: 14,
    status: 'Synced',
    uptime: '14d 05h 22m',
    version: '1.0.35'
  });

  // Initial state reflects the local device (Alpha) which is the primary deployment target
  const [clusterNodes, setClusterNodes] = useState<ClusterNode[]>([
    { 
        id: 'n1', 
        name: 'Pi-Alpha (Local Host)', 
        ip: '127.0.0.1', 
        hat: 'SSD_NVME', 
        status: 'online', 
        metrics: { cpu: 12, ram: 2.1, temp: 45, iops: 12500 } 
    }
  ]);

  const [sysStats, setSysStats] = useState<SystemStats>({
    cpu: 24, ram: 45, temp: 42, disk: 12
  });

  // Handle completion of setup wizard with detected nodes
  const handleSetupComplete = (nodes: ClusterNode[]) => {
      setClusterNodes(nodes);
      setIsSetupComplete(true);
  };

  useEffect(() => {
    const interval = setInterval(() => {
      setSysStats(prev => ({
        cpu: Math.max(10, Math.min(95, prev.cpu + (Math.random() * 10 - 5))),
        ram: Math.max(40, Math.min(60, prev.ram + (Math.random() * 2 - 1))),
        temp: Math.max(38, Math.min(65, prev.temp + (Math.random() * 4 - 2))),
        disk: prev.disk
      }));

      setClusterNodes(prev => prev.map(node => ({
        ...node,
        metrics: {
          ...node.metrics,
          cpu: Math.random() * 30 + 5,
          temp: Math.random() * 10 + 40,
          npu: node.hat === 'AI_NPU' ? Math.random() * 100 : undefined,
          iops: node.hat === 'SSD_NVME' ? Math.random() * 8000 + 12000 : undefined,
        }
      })));

      setNodeStats(prev => ({ ...prev, blockHeight: prev.blockHeight + 1 }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const openApp = (id: AppId) => {
    setWindows(prev => prev.map(w => {
      if (w.id === id) {
        return { ...w, isOpen: true, isMinimized: false, zIndex: Math.max(...prev.map(x => x.zIndex)) + 1 };
      }
      return w;
    }));
    setActiveId(id);
  };

  const closeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const minimizeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
  };

  const bringToFront = (id: AppId) => {
    const maxZ = Math.max(...windows.map(w => w.zIndex));
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: maxZ + 1, isMinimized: false } : w));
    setActiveId(id);
  };

  if (!isSetupComplete) {
    return <SetupWizard onComplete={handleSetupComplete} />;
  }

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-slate-950 flex flex-col font-sans select-none">
      <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_50%_50%,rgba(197,26,74,0.1),rgba(0,0,0,0))]" />
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />

      <TopBar nodeStats={nodeStats} systemStats={sysStats} />

      <main className="flex-1 relative overflow-hidden p-6 mt-10 mb-16">
        <Desktop openApp={openApp} />

        {windows.map(win => {
          if (!win.isOpen) return null;

          return (
            <div 
              key={win.id}
              style={{ zIndex: win.zIndex, display: win.isMinimized ? 'none' : 'block' }}
              className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-5xl h-[75vh]"
            >
              <WindowContainer 
                title={win.title} 
                onClose={() => closeApp(win.id)}
                onMinimize={() => minimizeApp(win.id)}
                onFocus={() => bringToFront(win.id)}
                isActive={activeId === win.id}
              >
                {win.id === 'minima-node' && <MinimaNodeApp stats={nodeStats} />}
                {win.id === 'system-monitor' && <SystemMonitorApp stats={sysStats} />}
                {win.id === 'terminal' && <TerminalApp />}
                {win.id === 'ai-assistant' && (
                  <AiAssistantApp 
                    context={{ 
                      node: nodeStats, 
                      cluster: clusterNodes, 
                      telemetry: sysStats,
                      timestamp: new Date().toISOString()
                    }} 
                  />
                )}
                {win.id === 'wallet' && <WalletApp />}
                {win.id === 'maxima-messenger' && <MaximaMessengerApp />}
                {win.id === 'cluster-manager' && <ClusterManagerApp nodes={clusterNodes} />}
                {win.id === 'depai-executor' && <DePAiExecutor nodes={clusterNodes} />}
                {win.id === 'imager-utility' && <ImagerUtility />}
                {win.id === 'file-explorer' && <FileExplorerApp />}
                {win.id === 'settings' && <SettingsApp />}
              </WindowContainer>
            </div>
          );
        })}
      </main>

      <Taskbar 
        windows={windows} 
        activeId={activeId} 
        onAppClick={(id) => {
          const win = windows.find(w => w.id === id);
          if (win?.isMinimized || !win?.isOpen) {
            openApp(id);
          } else if (activeId === id) {
            minimizeApp(id);
          } else {
            bringToFront(id);
          }
        }} 
      />
    </div>
  );
};

interface WindowContainerProps {
  title: string;
  onClose: () => void;
  onMinimize: () => void;
  onFocus: () => void;
  isActive: boolean;
  children: React.ReactNode;
}

const WindowContainer: React.FC<WindowContainerProps> = ({ title, onClose, onMinimize, onFocus, isActive, children }) => {
  return (
    <div 
      className={`flex flex-col w-full h-full glass-dark rounded-2xl overflow-hidden shadow-2xl transition-all duration-200 border-2 ${isActive ? 'border-blue-500/40 shadow-blue-500/10' : 'border-white/10'}`}
      onClick={onFocus}
    >
      <div className={`h-11 flex items-center justify-between px-5 border-b ${isActive ? 'bg-white/10 border-white/20' : 'bg-transparent border-white/5'}`}>
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isActive ? 'bg-blue-500 animate-pulse' : 'bg-slate-600'}`} />
          <span className="text-sm font-semibold text-slate-200 tracking-wide uppercase">{title}</span>
        </div>
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); onMinimize(); }} className="hover:text-white text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14" /></svg>
          </button>
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:text-red-500 text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M18 6L6 18M6 6l12 12" /></svg>
          </button>
        </div>
      </div>
      <div className="flex-1 overflow-auto bg-slate-900/60">
        {children}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ClusterNode } from '../../types';

interface SetupWizardProps {
  onComplete: (nodes: ClusterNode[]) => void;
}

const SetupWizard: React.FC<SetupWizardProps> = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [nodesFound, setNodesFound] = useState<ClusterNode[]>([
      { id: 'n1', name: 'Pi-Alpha (Local)', ip: '127.0.0.1', hat: 'SSD_NVME', status: 'online', metrics: { cpu: 12, ram: 2.1, temp: 45, iops: 12500 } }
  ]);

  const steps = [
    {
      title: "Welcome to PiNet Web3 OS",
      description: "The official Web3 distribution for Raspberry Pi by Minima. We'll help you configure your decentralized node.",
      icon: "🚀"
    },
    {
      title: "Initializing Minima Protocol",
      description: "Connecting to the global Minima network. Your node will be part of a purely decentralized ecosystem.",
      icon: "🌐"
    },
    {
      title: "Network Discovery",
      description: `Scanning local subnet for Raspberry Pi peers.`,
      icon: "📡"
    },
    {
      title: "Cluster Configuration",
      description: `Configuring ${nodesFound.length} Detected Node${nodesFound.length > 1 ? 's' : ''}. Assigning roles based on hardware Hats (NVMe, NPU, Sense).`,
      icon: "🔌"
    },
    {
      title: "Agentic Payments (M.402)",
      description: "Setting up the M.402 payment stream system for autonomous resource management.",
      icon: "💎"
    }
  ];

  // Simulated peer discovery
  const scanForPeers = () => {
      setLoading(true);
      setProgress(0);
      const interval = setInterval(() => {
        setProgress(p => {
          if (p >= 100) {
            clearInterval(interval);
            setLoading(false);
            // Simulate finding 2 more nodes
            setNodesFound([
                { id: 'n1', name: 'Pi-Alpha (NVMe Hub)', ip: '192.168.1.10', hat: 'SSD_NVME', status: 'online', metrics: { cpu: 12, ram: 2.1, temp: 45, iops: 12500 } },
                { id: 'n2', name: 'Pi-Beta (AI Hub)', ip: '192.168.1.11', hat: 'AI_NPU', status: 'online', metrics: { cpu: 8, ram: 1.4, temp: 42, npu: 15 } },
                { id: 'n3', name: 'Pi-Gamma (Sense)', ip: '192.168.1.12', hat: 'SENSE', status: 'online', metrics: { cpu: 15, ram: 3.2, temp: 48, env: { temp: 22.4, humidity: 45, pressure: 1012 } } },
            ]);
            return 100;
          }
          return p + 5;
        });
      }, 30);
  };

  const nextStep = () => {
    if (step === 2 && nodesFound.length === 1 && !loading) {
       // Allow user to choose to scan or proceed
       setStep(step + 1);
       return;
    }

    if (step < steps.length - 1) {
      setLoading(true);
      setProgress(0);
      const interval = setInterval(() => {
        setProgress(p => {
          if (p >= 100) {
            clearInterval(interval);
            setLoading(false);
            setStep(step + 1);
            return 100;
          }
          return p + 4; // speed
        });
      }, 40);
    } else {
      onComplete(nodesFound);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex items-center justify-center p-6 overflow-hidden">
      <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_50%_50%,rgba(197,26,74,0.15),rgba(0,0,0,0))]" />
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />

      <div className="max-w-xl w-full glass-dark rounded-[2.5rem] border border-white/10 p-12 relative z-10 shadow-2xl flex flex-col gap-8 text-center">
        <div className="flex justify-center">
          <div className="w-24 h-24 rounded-3xl bg-[#C51A4A] flex items-center justify-center text-5xl shadow-2xl shadow-pink-500/20 animate-bounce">
            {steps[step].icon}
          </div>
        </div>

        <div className="space-y-4">
          <h1 className="text-4xl font-black text-white tracking-tighter uppercase italic">{steps[step].title}</h1>
          <p className="text-slate-400 text-lg font-medium leading-relaxed">
            {step === 2 && nodesFound.length === 1 && !loading ? "We found 1 device (Local Host). Do you want to scan for cluster peers?" : steps[step].description}
          </p>
          {step === 2 && nodesFound.length > 1 && (
              <p className="text-emerald-400 font-bold animate-pulse">Successfully detected full cluster topology!</p>
          )}
        </div>

        {step === 2 && !loading ? (
             <div className="pt-6 flex gap-4 justify-center">
                {nodesFound.length === 1 && (
                    <button 
                        onClick={scanForPeers}
                        className="px-8 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-md font-bold uppercase tracking-widest shadow-xl transition-all hover:scale-105 active:scale-95"
                    >
                        Scan Subnet
                    </button>
                )}
                <button 
                    onClick={() => setStep(step + 1)}
                    className="px-8 py-4 bg-pink-600 hover:bg-pink-500 text-white rounded-2xl text-md font-bold uppercase tracking-widest shadow-xl shadow-pink-900/40 transition-all hover:scale-105 active:scale-95"
                >
                    {nodesFound.length === 1 ? "Use Single Node" : "Continue"}
                </button>
             </div>
        ) : loading ? (
          <div className="space-y-4">
            <div className="h-3 w-full bg-white/5 rounded-full overflow-hidden border border-white/10">
              <div className="h-full bg-pink-600 transition-all duration-100" style={{ width: `${progress}%` }} />
            </div>
            <p className="text-[10px] font-bold text-pink-500 uppercase tracking-[0.3em]">
                {step === 2 ? "Probing Network..." : "Deploying OS Components..."}
            </p>
          </div>
        ) : (
          <div className="pt-6">
            <button 
              onClick={nextStep}
              className="px-10 py-5 bg-pink-600 hover:bg-pink-500 text-white rounded-2xl text-lg font-black uppercase tracking-widest shadow-xl shadow-pink-900/40 transition-all hover:scale-105 active:scale-95"
            >
              {step === steps.length - 1 ? "Launch OS" : "Continue"}
            </button>
          </div>
        )}

        {/* Steps Indicator */}
        <div className="mt-8 flex justify-center gap-2">
            {steps.map((_, i) => (
            <div key={i} className={`h-1.5 rounded-full transition-all duration-500 ${i === step ? 'w-8 bg-pink-500' : 'w-2 bg-white/10'}`} />
            ))}
        </div>

        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
          <svg className="w-4 h-4 text-[#C51A4A]" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 14.5v-9l6 4.5-6 4.5z"/></svg>
          PiNet Web3 OS Core
        </div>
      </div>
    </div>
  );
};

export default SetupWizard;

import React, { useState } from 'react';
import { ClusterNode } from '../../types';

interface ClusterManagerAppProps {
  nodes: ClusterNode[];
}

const ClusterManagerApp: React.FC<ClusterManagerAppProps> = ({ nodes }) => {
  const [provisioningId, setProvisioningId] = useState<string | null>(null);
  const [isBroadcasting, setIsBroadcasting] = useState(false);

  const startProvisioning = (id: string) => {
    setProvisioningId(id);
    setTimeout(() => setProvisioningId(null), 5000);
  };

  const toggleBroadcast = () => {
    setIsBroadcasting(!isBroadcasting);
  };

  return (
    <div className="p-8 h-full space-y-8 overflow-y-auto">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-[#C51A4A] rounded-2xl flex items-center justify-center shadow-lg shadow-pink-900/20 border border-white/10">
            <svg className="w-7 h-7 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 22a2 2 0 1 0 0-4 2 2 0 0 0 0 4Z"/><path d="M5 12a2 2 0 1 0 0-4 2 2 0 0 0 0 4Z"/><path d="M19 12a2 2 0 1 0 0-4 2 2 0 0 0 0 4Z"/><path d="M12 6a2 2 0 1 0 0-4 2 2 0 0 0 0 4Z"/><path d="m8 10 3-3"/><path d="m13 7 3 3"/><path d="m13 18-1-12"/><path d="m17 11-4 7"/><path d="m7 11 4 7"/></svg>
          </div>
          <div>
            <h1 className="text-3xl font-bold text-white tracking-tight">Cluster Orchestrator</h1>
            <p className="text-slate-400 font-medium italic">OS Multi-Pi Deployment Engine • PXE Discovery</p>
          </div>
        </div>
        <div className="flex gap-3">
           <button 
              onClick={toggleBroadcast}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all shadow-lg active:scale-95 ${isBroadcasting ? 'bg-emerald-600 animate-pulse' : 'bg-white/5 border border-white/10 text-slate-300'}`}
           >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" strokeWidth="2"><path d="M18.36 5.64a9 9 0 1 1-12.73 0M12 2v10"/></svg>
              {isBroadcasting ? 'Broadcasting OS Image...' : 'Broadcast OS to Network'}
           </button>
           <span className="px-4 py-2 bg-emerald-500/10 text-emerald-400 text-[10px] font-bold rounded-xl border border-emerald-500/20 uppercase tracking-[0.2em] flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
              {nodes.length} Node{nodes.length !== 1 ? 's' : ''} Synced
           </span>
        </div>
      </div>

      <div className={`grid grid-cols-1 ${nodes.length === 1 ? 'md:grid-cols-1 max-w-xl mx-auto' : 'md:grid-cols-3'} gap-6`}>
        {nodes.map(node => (
          <NodeCard 
            key={node.id} 
            node={node} 
            isProvisioning={provisioningId === node.id} 
            onProvision={() => startProvisioning(node.id)} 
            isBroadcastMode={isBroadcasting}
          />
        ))}
        {/* Placeholder slots for up to 3 nodes simulation */}
        {nodes.length < 3 && isBroadcasting && (
             <div className="glass-dark p-6 rounded-[2.5rem] border border-white/10 border-dashed flex flex-col items-center justify-center opacity-50 min-h-[300px]">
                 <div className="w-12 h-12 rounded-full bg-slate-800 animate-pulse flex items-center justify-center">
                    <svg className="w-6 h-6 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9"/></svg>
                 </div>
                 <div className="mt-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Searching...</div>
             </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-8">
        <div className="glass-dark p-6 rounded-[2rem] border border-white/5 space-y-5">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <svg className="w-4 h-4 text-pink-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>
                Provisioning Topology
            </h3>
            <div className="relative h-56 border border-white/10 rounded-2xl bg-black/40 overflow-hidden flex items-center justify-center">
                <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/grid-me.png')]" />
                <div className="flex items-center gap-4 sm:gap-12 z-10">
                    {nodes.map((node, i) => (
                        <React.Fragment key={node.id}>
                            <TopologyNode 
                                label={i === 0 ? "α" : i === 1 ? "β" : "γ"} 
                                color={i === 0 ? "border-pink-500" : i === 1 ? "border-emerald-500" : "border-amber-500"} 
                                glow={i === 0 ? "shadow-pink-500/30" : i === 1 ? "shadow-emerald-500/30" : "shadow-amber-500/30"} 
                            />
                            {i < nodes.length - 1 && (
                                <div className="relative w-10 sm:w-20 h-px bg-white/10">
                                    <div className={`absolute inset-0 bg-gradient-to-r ${i===0 ? 'from-pink-500 to-emerald-500' : 'from-emerald-500 to-amber-500'} ${isBroadcasting ? 'animate-[ping_1.5s_infinite]' : ''}`} />
                                </div>
                            )}
                        </React.Fragment>
                    ))}
                    {nodes.length === 1 && (
                        <div className="text-[10px] text-slate-600 font-mono absolute bottom-4">Single Node Mode</div>
                    )}
                </div>
            </div>
        </div>

        <div className="glass-dark p-6 rounded-[2rem] border border-white/5 space-y-6">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <svg className="w-4 h-4 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0z"/></svg>
                Web3 Imager Configuration
            </h3>
            <div className="space-y-6">
                <div className="flex justify-between items-end">
                    <div className="flex flex-col">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">OS Image Version</span>
                        <div className="text-3xl font-mono font-bold text-pink-500 tracking-tighter">1.0.35-STABLE</div>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Architecture</span>
                        <span className="text-sm font-mono text-white font-bold">AARCH64 (v8.1)</span>
                    </div>
                </div>
                <div className="p-4 rounded-xl bg-white/5 border border-white/10 text-[11px] font-mono text-slate-400">
                    pinet-cluster discovery=auto pxe=enabled burn=m402
