import React, { useState, useEffect } from 'react';
import Desktop from './components/Desktop';
import Taskbar from './components/Taskbar';
import TopBar from './components/TopBar';
import SetupWizard from './components/apps/SetupWizard';
import { AppId, WindowState, NodeStats, SystemStats, ClusterNode } from './types';
import MinimaNodeApp from './components/apps/MinimaNodeApp';
import SystemMonitorApp from './components/apps/SystemMonitorApp';
import TerminalApp from './components/apps/TerminalApp';
import AiAssistantApp from './components/apps/AiAssistantApp';
import WalletApp from './components/apps/WalletApp';
import MaximaMessengerApp from './components/apps/MaximaMessengerApp';
import ClusterManagerApp from './components/apps/ClusterManagerApp';
import DePAiExecutor from './components/apps/DePAiExecutor';
import ImagerUtility from './components/apps/ImagerUtility';
import FileExplorerApp from './components/apps/FileExplorerApp';
import SettingsApp from './components/apps/SettingsApp';
import VisualAssetStudio from './components/apps/VisualAssetStudio';
import { minimaService } from './services/minimaService';
import { clusterService } from './services/clusterService';
import { settingsService } from './services/settingsService';

const App: React.FC = () => {
  const [isSetupComplete, setIsSetupComplete] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'minima-node', title: 'Minima Node', isOpen: true, isMinimized: false, zIndex: 10 },
    { id: 'system-monitor', title: 'System Monitor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'terminal', title: 'PiNet Shell', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'ai-assistant', title: 'PiNet AI Assistant', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'wallet', title: 'Web3 Wallet', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'maxima-messenger', title: 'Maxima Messenger', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'cluster-manager', title: 'Cluster Hub', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'depai-executor', title: 'DePAI Executor', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'imager-utility', title: 'Pi Imager Config', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'file-explorer', title: 'File Explorer', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'settings', title: 'System Settings', isOpen: false, isMinimized: false, zIndex: 1 },
    { id: 'visual-studio', title: 'Visual Asset Studio', isOpen: false, isMinimized: false, zIndex: 1 },
  ]);

  const [activeId, setActiveId] = useState<AppId>('minima-node');
  const [nodeStats, setNodeStats] = useState<NodeStats>(minimaService.stats);
  const [clusterNodes, setClusterNodes] = useState<ClusterNode[]>(clusterService.nodes);
  const [wallpaper, setWallpaper] = useState(settingsService.wallpaper);

  const [sysStats, setSysStats] = useState<SystemStats>({
    cpu: 24, ram: 45, temp: 42, disk: 12
  });

  // Subscriptions to services
  useEffect(() => {
    const unsubMinima = minimaService.subscribe(() => {
        setNodeStats({...minimaService.stats});
    });
    const unsubCluster = clusterService.subscribe(() => {
        setClusterNodes([...clusterService.nodes]);
    });
    const unsubSettings = settingsService.subscribe(() => {
        setWallpaper(settingsService.wallpaper);
    });

    return () => {
        unsubMinima();
        unsubCluster();
        unsubSettings();
    };
  }, []);

  // Handle completion of setup wizard with detected nodes
  const handleSetupComplete = (nodes: ClusterNode[]) => {
      clusterService.setNodes(nodes);
      setIsSetupComplete(true);
  };

  useEffect(() => {
    const interval = setInterval(() => {
      setSysStats(prev => ({
        cpu: Math.max(10, Math.min(95, prev.cpu + (Math.random() * 10 - 5))),
        ram: Math.max(40, Math.min(60, prev.ram + (Math.random() * 2 - 1))),
        temp: Math.max(38, Math.min(65, prev.temp + (Math.random() * 4 - 2))),
        disk: prev.disk
      }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const openApp = (id: AppId) => {
    setWindows(prev => prev.map(w => {
      if (w.id === id) {
        return { ...w, isOpen: true, isMinimized: false, zIndex: Math.max(...prev.map(x => x.zIndex)) + 1 };
      }
      return w;
    }));
    setActiveId(id);
  };

  const closeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const minimizeApp = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
  };

  const bringToFront = (id: AppId) => {
    const maxZ = Math.max(...windows.map(w => w.zIndex));
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: maxZ + 1, isMinimized: false } : w));
    setActiveId(id);
  };

  const getWallpaperUrl = () => {
      switch(wallpaper) {
          case 'neon': return "url('https://images.unsplash.com/photo-1550751827-4bd374c3f58b?q=80&w=2670')";
          case 'space': return "url('https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=2672')";
          case 'mesh': return "url('https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=2564')";
          default: return "url('https://www.transparenttextures.com/patterns/carbon-fibre.png')";
      }
  };

  if (!isSetupComplete) {
    return <SetupWizard onComplete={handleSetupComplete} />;
  }

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-slate-950 flex flex-col font-sans select-none transition-all duration-700"
         style={{ 
             backgroundImage: wallpaper !== 'carbon' ? getWallpaperUrl() : 'none',
             backgroundSize: 'cover',
             backgroundPosition: 'center'
         }}>
      {wallpaper === 'carbon' && (
          <div className="absolute top-0 left-0 w-full h-full pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />
      )}
      <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_50%_50%,rgba(197,26,74,0.1),rgba(0,0,0,0))]" />

      <TopBar nodeStats={nodeStats} systemStats={sysStats} />

      <main className="flex-1 relative overflow-hidden p-6 mt-10 mb-16">
        <Desktop openApp={openApp} />

        {windows.map(win => {
          if (!win.isOpen) return null;

          return (
            <div 
              key={win.id}
              style={{ zIndex: win.zIndex, display: win.isMinimized ? 'none' : 'block' }}
              className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-5xl h-[75vh]"
            >
              <WindowContainer 
                title={win.title} 
                onClose={() => closeApp(win.id)}
                onMinimize={() => minimizeApp(win.id)}
                onFocus={() => bringToFront(win.id)}
                isActive={activeId === win.id}
              >
                {win.id === 'minima-node' && <MinimaNodeApp stats={nodeStats} />}
                {win.id === 'system-monitor' && <SystemMonitorApp stats={sysStats} />}
                {win.id === 'terminal' && <TerminalApp />}
                {win.id === 'ai-assistant' && (
                  <AiAssistantApp 
                    context={{ 
                      node: nodeStats, 
                      cluster: clusterNodes, 
                      telemetry: sysStats,
                      timestamp: new Date().toISOString()
                    }} 
                  />
                )}
                {win.id === 'wallet' && <WalletApp />}
                {win.id === 'maxima-messenger' && <MaximaMessengerApp />}
                {win.id === 'cluster-manager' && <ClusterManagerApp nodes={clusterNodes} />}
                {win.id === 'depai-executor' && <DePAiExecutor nodes={clusterNodes} />}
                {win.id === 'imager-utility' && <ImagerUtility />}
                {win.id === 'file-explorer' && <FileExplorerApp />}
                {win.id === 'settings' && <SettingsApp />}
                {win.id === 'visual-studio' && <VisualAssetStudio />}
              </WindowContainer>
            </div>
          );
        })}
      </main>

      <Taskbar 
        windows={windows} 
        activeId={activeId} 
        onAppClick={(id) => {
          const win = windows.find(w => w.id === id);
          if (win?.isMinimized || !win?.isOpen) {
            openApp(id);
          } else if (activeId === id) {
            minimizeApp(id);
          } else {
            bringToFront(id);
          }
        }} 
      />
    </div>
  );
};

interface WindowContainerProps {
  title: string;
  onClose: () => void;
  onMinimize: () => void;
  onFocus: () => void;
  isActive: boolean;
  children: React.ReactNode;
}

const WindowContainer: React.FC<WindowContainerProps> = ({ title, onClose, onMinimize, onFocus, isActive, children }) => {
  return (
    <div 
      className={`flex flex-col w-full h-full glass-dark rounded-2xl overflow-hidden shadow-2xl transition-all duration-200 border-2 ${isActive ? 'border-blue-500/40 shadow-blue-500/10' : 'border-white/10'}`}
      onClick={onFocus}
    >
      <div className={`h-11 flex items-center justify-between px-5 border-b ${isActive ? 'bg-white/10 border-white/20' : 'bg-transparent border-white/5'}`}>
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isActive ? 'bg-blue-500 animate-pulse' : 'bg-slate-600'}`} />
          <span className="text-sm font-semibold text-slate-200 tracking-wide uppercase">{title}</span>
        </div>
        <div className="flex items-center gap-4">
          <button onClick={(e) => { e.stopPropagation(); onMinimize(); }} className="hover:text-white text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14" /></svg>
          </button>
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="hover:text-red-500 text-slate-500 transition-colors">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M18 6L6 18M6 6l12 12" /></svg>
          </button>
        </div>
      </div>
      <div className="flex-1 overflow-auto bg-slate-900/60">
        {children}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { shell } from '../../services/shellService';
import { VFSNode } from '../../types';

const FileExplorerApp: React.FC = () => {
  const [currentPath, setCurrentPath] = useState(shell.getCurrentPath());
  const [nodes, setNodes] = useState<VFSNode[]>([]);

  useEffect(() => {
    updateView();
  }, [currentPath]);

  const updateView = () => {
      const dir = shell.resolvePath(currentPath);
      if (dir && dir.children) {
          setNodes(dir.children);
      } else {
          setNodes([]);
      }
  };

  const navigate = (folderName: string) => {
      const newPath = currentPath === '/' ? `/${folderName}` : `${currentPath}/${folderName}`;
      // In a real app we'd verify it exists first, but shell logic is simple
      setCurrentPath(newPath);
  };

  const goUp = () => {
      if (currentPath === '/') return;
      const parts = currentPath.split('/').filter(Boolean);
      parts.pop();
      setCurrentPath('/' + parts.join('/'));
  };

  return (
    <div className="flex h-full flex-col bg-slate-900/40">
      <div className="flex items-center gap-4 p-4 border-b border-white/5 bg-black/20">
        <div className="flex gap-2">
            <button 
                onClick={goUp}
                disabled={currentPath === '/'}
                className="p-2 hover:bg-white/5 rounded-lg text-slate-400 transition-colors disabled:opacity-30"
            >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
            </button>
            <button className="p-2 hover:bg-white/5 rounded-lg text-slate-400 transition-colors">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M14 5l7 7m0 0l-7 7m7-7H3"/></svg>
            </button>
        </div>
        <div className="flex-1">
            <div className="bg-black/40 border border-white/10 rounded-xl px-4 py-2 text-xs font-mono text-slate-300 flex items-center gap-2">
                <svg className="w-3 h-3 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z"/></svg>
                {currentPath}
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-auto p-4">
        <table className="w-full text-left text-xs text-slate-400">
            <thead className="text-[10px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/5">
                <tr>
                    <th className="pb-3 pl-4">Name</th>
                    <th className="pb-3">Type</th>
                    <th className="pb-3">Modified</th>
                    <th className="pb-3">Size</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
                {currentPath !== '/' && (
                    <tr onClick={goUp} className="hover:bg-white/5 transition-colors cursor-pointer group">
                        <td className="py-3 pl-4 flex items-center gap-3">
                            <div className="text-slate-400">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z"/></svg>
                            </div>
                            <span className="text-white font-medium group-hover:text-blue-400 transition-colors">..</span>
                        </td>
                        <td className="py-3 font-mono opacity-60 uppercase">DIR</td>
                        <td className="py-3 opacity-60"></td>
                        <td className="py-3 opacity-60 font-mono"></td>
                    </tr>
                )}
                {nodes.map((node, i) => (
                    <tr 
                        key={i} 
                        onClick={() => node.type === 'dir' && navigate(node.name)}
                        className="hover:bg-white/5 transition-colors cursor-pointer group"
                    >
                        <td className="py-3 pl-4 flex items-center gap-3">
                            <div className={node.type === 'dir' ? 'text-blue-400' : 'text-slate-400'}>
                                {node.type === 'dir' ? (
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 7v10a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-6l-2-2H5a2 2 0 00-2 2z"/></svg>
                                ) : (
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z"/></svg>
                                )}
                            </div>
                            <span className="text-white font-medium group-hover:text-blue-400 transition-colors">{node.name}</span>
                        </td>
                        <td className="py-3 font-mono opacity-60 uppercase">{node.type}</td>
                        <td className="py-3 opacity-60">{new Date(node.modified).toLocaleDateString()}</td>
                        <td className="py-3 opacity-60 font-mono">{node.size ? node.size.toLocaleString() : '--'}</td>
                    </tr>
                ))}
            </tbody>
        </table>
      </div>
    </div>
  );
};

