          </h3>
          <div className="max-h-[300px] overflow-y-auto pr-2 space-y-3">
            {activeSessions.length === 0 ? (
              <div className="text-center py-8 text-slate-600 text-[10px] italic border border-dashed border-white/10 rounded-2xl">
