                    name: args[0],
                    type: 'dir',
                    modified: Date.now(),
                    permissions: 'drwxr-xr-x',
                    children: []
                });
                // Silent success in linux usually
            } else {
                output.push({ text: `mkdir: cannot create directory '${args[0]}': No such file or directory`, type: 'error' });
