    // If only local node is found, proceed to next step which effectively means "Use Single Node"
    if (step === 2 && nodesFound.length === 1 && !loading) {
       setStep(step + 1);
       return;
    }

    if (step < steps.length - 1) {
      setLoading(true);
      setProgress(0);
