        ) : loading && step !== 2 ? (
          <div className="space-y-4">
            <div className="h-3 w-full bg-white/5 rounded-full overflow-hidden border border-white/10">
              <div className="h-full bg-pink-600 transition-all duration-100" style={{ width: `${progress}%` }} />
