        break;

      case 'top':
        output.push(
          { text: 'top - 14:22:15 up 2 days, 14:12,  1 user,  load average: 0.12, 0.08, 0.02', type: 'header' },
          { text: 'Tasks: 142 total,   2 running, 140 sleeping,   0 stopped,   0 zombie', type: 'info' },
